console.log('╠════════════════════════════════════════╣');
console.log(`║ Mood: ${(blessing as any).mood.padEnd(29)} ║`);
console.log(`║ Quality: ${(blessing as any).quality.padEnd(26)} ║`);
console.log('╠════════════════════════════════════════╣');
console.log(poem.split('\n').map(l => '║ ' + l.padEnd(36) + ' ║').join('\n'));
console.log('╚════════════════════════════════════════╝');
